// Alertmanager sends 1 webhook with N alerts → loop
const body = $input.item.json.body || $input.item.json;
const alerts = body.alerts || [];

// Filter: only firing critical alerts
const critical = alerts.filter(a =>
  a.status === 'firing' &&
  (a.labels.severity === 'critical' || a.labels.priority?.match(/p[01]|P[01]/))
);

return critical.map(alert => ({
  alertname: alert.labels.alertname || 'unknown',
  severity: alert.labels.severity || '?',
  priority: alert.labels.priority || '?',
  namespace: alert.labels.namespace || '?',
  pod: alert.labels.pod || '',
  service: alert.labels.service || alert.labels.service_name || '',
  summary: alert.annotations.summary || '',
  description: alert.annotations.description || '',
  startsAt: alert.startsAt,
  generatorURL: alert.generatorURL || '',
  runbook_url: alert.annotations.runbook_url || '',
  dashboard_url: alert.annotations.dashboard_url || '',
  query_url: alert.annotations.query_url || '',
  raw_labels: alert.labels
}));

